export interface CookieOptions {
  expires?: number | Date
  path?: string
  domain?: string
  secure?: boolean
  sameSite?: 'Strict' | 'Lax' | 'None'
}

export function setCookieItem(
  key: string,
  value: string,
  options: CookieOptions = {}
): string {
  let expires = ''
  if (options.expires != null) {
    let expiresDate: Date
    if (typeof options.expires === 'number') {
      expiresDate = new Date()
      expiresDate.setTime(expiresDate.getTime() + options.expires * 864e5)
    } else {
      expiresDate = options.expires
    }
    expires = '; expires=' + expiresDate.toUTCString()
  }

  return (document.cookie = [
    encodeURIComponent(key) + '=' + encodeURIComponent(String(value)),
    expires,
    options.path ? '; path=' + options.path : '',
    options.domain ? '; domain=' + options.domain : '',
    options.secure ? '; secure' : '',
    options.sameSite ? '; SameSite=' + options.sameSite : '',
  ].join(''))
}

export function getCookieItem(cookieName: string): string | null {
  const encodedName = encodeURIComponent(cookieName) + '='
  const cookies = document.cookie.split(';')
  for (const cookie of cookies) {
    const trimmed = cookie.trim()
    if (trimmed.startsWith(encodedName)) {
      return decodeURIComponent(trimmed.substring(encodedName.length))
    }
  }
  return null
}
