import { createHttpClient, VibeCoderError } from './core/https'
import { DataClient } from './modules/entities'
import { createAuthModule } from './modules/auth'
import {
  getAccessToken,
  saveAccessToken,
  removeAccessToken,
} from './utils/auth-utils'
import * as Utils from './utils'
import type { VibeCoderConfig } from './types'

export { DataClient, Utils }

export function createClient(config: VibeCoderConfig) {
  const {
    serverUrl = 'https://openhands.strikingly.com',
    appId,
    token,
    requiresAuth = false,
    appBaseUrl,
    headers: optionalHeaders = {},
    options,
  } = config

  const headers = {
    ...optionalHeaders,
    'X-App-Id': String(appId),
  }

  // Create HTTP client
  const axiosClient = createHttpClient({
    baseURL: `${serverUrl}/api`,
    headers,
    token,
    onError: options?.onError,
  })

  // Create modules
  const userModules = {
    auth: createAuthModule(axiosClient, appId, {
      appBaseUrl,
      serverUrl,
    }),
  }

  // Auto-set token from localStorage if available
  if (typeof window !== 'undefined') {
    const accessToken = token || getAccessToken()
    if (accessToken) {
      userModules.auth.setToken(accessToken)
    }
  }

  // Auto-redirect to login if required
  if (requiresAuth && typeof window !== 'undefined') {
    setTimeout(async () => {
      try {
        const isAuthenticated = await userModules.auth.isAuthenticated()
        if (!isAuthenticated) {
          userModules.auth.redirectToLogin(window.location.href)
        }
      } catch (error) {
        console.error('Authentication check failed:', error)
        userModules.auth.redirectToLogin(window.location.href)
      }
    }, 0)
  }

  return {
    ...userModules,
    setToken(newToken: string) {
      userModules.auth.setToken(newToken)
    },
    getConfig() {
      return { serverUrl, appId, requiresAuth }
    },
  }
}

export * from './types'

export { VibeCoderError, getAccessToken, saveAccessToken, removeAccessToken }
