import axios, { AxiosInstance } from 'axios'
import { AuthMethods } from '../types'

type LoginResponse = {
  access_token?: string
  user?: unknown
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null
}

export function createAuthModule(
  client: AxiosInstance,
  appId: string,
  options: { appBaseUrl?: string; serverUrl?: string }
): AuthMethods {
  return {
    async user() {
      return client.get(`/v1/sites/${appId}/form_entities/user`)
    },

    async updateUser(data: unknown) {
      return client.put(`/v1/sites/${appId}/form_entities/user`, data)
    },

    redirectToLogin(nextUrl?: string) {
      if (typeof window === 'undefined') {
        throw new Error(
          'Login method can only be used in a browser environment'
        )
      }
      const redirectUrl = nextUrl
        ? new URL(nextUrl, window.location.origin).toString()
        : window.location.href
      const loginUrl = `${
        options.appBaseUrl || ''
      }/login?from_url=${encodeURIComponent(redirectUrl)}`
      window.location.href = loginUrl
    },

    logout(redirectUrl?: string) {
      delete client.defaults.headers.common.Authorization
      if (typeof window !== 'undefined' && window.localStorage) {
        try {
          window.localStorage.removeItem('vibe_coder_access_token')
          window.localStorage.removeItem('token')
        } catch (e) {
          console.error('Failed to remove token from localStorage:', e)
        }
      }
      if (typeof window !== 'undefined') {
        if (redirectUrl) {
          window.location.href = redirectUrl
        } else {
          window.location.reload()
        }
      }
    },

    setToken(token: string, saveToStorage = true) {
      if (!token) return
      client.defaults.headers.common.Authorization = `Bearer ${token}`
      if (
        saveToStorage &&
        typeof window !== 'undefined' &&
        window.localStorage
      ) {
        try {
          window.localStorage.setItem('vibe_coder_access_token', token)
          window.localStorage.setItem('token', token)
        } catch (e) {
          console.error('Failed to save token to localStorage:', e)
        }
      }
    },

    async loginViaEmailPassword(
      email: string,
      password: string,
      turnstileToken?: string
    ) {
      try {
        const response = await client.post(`/apps/${appId}/auth/login`, {
          email,
          password,
          ...(turnstileToken && { turnstile_token: turnstileToken }),
        })

        const data: LoginResponse = isRecord(response)
          ? {
              access_token:
                typeof response.access_token === 'string'
                  ? response.access_token
                  : undefined,
              user: response.user,
            }
          : isRecord((response as { data?: unknown })?.data)
            ? {
                access_token:
                  typeof (response as { data: Record<string, unknown> }).data
                    .access_token === 'string'
                    ? ((response as { data: Record<string, unknown> }).data
                        .access_token as string)
                    : undefined,
                user: (response as { data: Record<string, unknown> }).data.user,
              }
            : {}

        const { access_token, user } = data
        if (access_token) {
          this.setToken(access_token)
        }
        return { access_token, user }
      } catch (error: unknown) {
        if (axios.isAxiosError(error) && error.response?.status === 401) {
          await this.logout()
        }
        throw error
      }
    },

    async isAuthenticated() {
      try {
        await this.user()
        return true
      } catch {
        return false
      }
    },

    async inviteUser(userEmail: string, role: string) {
      return client.post(`/apps/${appId}/users/invite-user`, {
        user_email: userEmail,
        role,
      })
    },

    async register(payload: unknown) {
      return client.post(`/apps/${appId}/auth/register`, payload)
    },

    async verifyOtp({ email, otpCode }: { email: string; otpCode: string }) {
      return client.post(`/apps/${appId}/auth/verify-otp`, {
        email,
        otp_code: otpCode,
      })
    },

    async resendOtp(email: string) {
      return client.post(`/apps/${appId}/auth/resend-otp`, { email })
    },

    async resetPasswordRequest(email: string) {
      return client.post(`/apps/${appId}/auth/reset-password-request`, { email })
    },

    async resetPassword({
      resetToken,
      newPassword,
    }: {
      resetToken: string
      newPassword: string
    }) {
      return client.post(`/apps/${appId}/auth/reset-password`, {
        reset_token: resetToken,
        new_password: newPassword,
      })
    },

    async changePassword({
      userId,
      currentPassword,
      newPassword,
    }: {
      userId: string
      currentPassword: string
      newPassword: string
    }) {
      return client.post(`/apps/${appId}/auth/change-password`, {
        user_id: userId,
        current_password: currentPassword,
        new_password: newPassword,
      })
    },
  }
}
